function getQuery(name) {
    return msg.req && msg.req.query ? msg.req.query[name] : undefined;
}

function decodeFormPart(value) {
    const normalized = String(value || '').replace(/\+/g, ' ');
    try {
        return decodeURIComponent(normalized);
    } catch (error) {
        return normalized;
    }
}

function parseFormBody(value) {
    const parsed = {};
    String(value || '').split('&').forEach((pair) => {
        if (!pair) return;
        const separatorIndex = pair.indexOf('=');
        const rawKey = separatorIndex >= 0 ? pair.slice(0, separatorIndex) : pair;
        const rawValue = separatorIndex >= 0 ? pair.slice(separatorIndex + 1) : '';
        const key = decodeFormPart(rawKey).trim();
        if (!key) return;
        parsed[key] = decodeFormPart(rawValue);
    });
    return parsed;
}

function parseBody(value) {
    if (Buffer.isBuffer(value)) {
        value = value.toString('utf8');
    }

    if (value && typeof value === 'object' && !Array.isArray(value)) {
        return value;
    }

    if (typeof value !== 'string') {
        return {};
    }

    const trimmed = value.trim();
    if (!trimmed) {
        return {};
    }

    if (trimmed.startsWith('{')) {
        try {
            return JSON.parse(trimmed);
        } catch (error) {
            node.warn('Unable to parse JSON client/con body: ' + error.message);
        }
    }

    const parsed = parseFormBody(trimmed);
    if (Object.keys(parsed).length > 0) {
        return parsed;
    }

    return { raw: trimmed };
}

function clean(value) {
    return String(value || '').trim();
}

const body = parseBody(
    msg.payloadRaw !== undefined ? msg.payloadRaw :
    msg.req && msg.req.body !== undefined ? msg.req.body :
    msg.payload
);

const moduleId = clean(
    body.uuid ||
    body.deviceUuid ||
    msg.module ||
    msg.moduleid ||
    getQuery('uuid') ||
    getQuery('deviceUuid')
);

const hardwareVersion = clean(
    body.hardware ||
    body.hw ||
    body.version ||
    body.firmwareVersion ||
    body.raw
);

if (!moduleId || !hardwareVersion) {
    msg._clientConFirmwareIgnored = {
        reason: !moduleId ? 'missing uuid' : 'missing hardware version',
        uuid: moduleId,
        payload: msg.payload,
        body
    };
    return [null, msg];
}

const receivedAt = new Date().toISOString();
msg._clientConFirmware = {
    moduleId,
    hardwareVersion,
    rawHardware: hardwareVersion,
    simUUID: clean(getQuery('simUUID')),
    simMobile: clean(getQuery('simMobile')),
    deviceId: clean(getQuery('deviceId')),
    ssl: clean(getQuery('ssl')),
    screen: clean(getQuery('screen')),
    sign: clean(getQuery('sign')),
    method: msg.req && msg.req.method ? msg.req.method : '',
    url: msg.req && msg.req.originalUrl ? msg.req.originalUrl : msg.req && msg.req.url ? msg.req.url : '',
    receivedAt
};

msg.payload = {
    path: 'kiosks',
    query: []
};

return [msg, null];

const docs = Array.isArray(msg.payload) ? msg.payload : [];
const info = msg._clientConFirmware || {};
const moduleId = String(info.moduleId || '').trim();
const hardwareVersion = String(info.hardwareVersion || '').trim();
const receivedAt = info.receivedAt || new Date().toISOString();
const aliasMap = flow.get('clientConFirmwareModuleAliases') || {};

function normalize(value) {
    return String(value || '').trim();
}

function addCandidate(candidates, value) {
    const normalized = normalize(value);
    if (normalized && candidates.indexOf(normalized) === -1) {
        candidates.push(normalized);
    }
}

function idsMatch(left, right) {
    const a = normalize(left);
    const b = normalize(right);
    if (!a || !b) return false;
    if (a === b) return true;
    if (('1000' + a) === b) return true;
    if (a === b.replace(/^1000/, '')) return true;
    return false;
}

function clone(value) {
    return JSON.parse(JSON.stringify(value));
}

function parseVersionNumber(value) {
    const text = String(value || '');
    const match = text.match(/(?:^|[-_])V?(\d{3,5})(?:\b|[-_.]|$)/i) || text.match(/V(\d{3,5})/i);
    if (!match) return null;
    const parsed = Number(match[1]);
    return Number.isFinite(parsed) ? parsed : null;
}

function moduleMatchesCandidate(module, candidateId) {
    return idsMatch(module && module.id, candidateId) ||
        idsMatch(module && module.moduleid, candidateId) ||
        idsMatch(module && module.uuid, candidateId) ||
        idsMatch(module && module.clientConUuid, candidateId) ||
        idsMatch(module && module.authUuid, candidateId) ||
        idsMatch(module && module.iotUuid, candidateId) ||
        idsMatch(module && module.mcuUuid, candidateId) ||
        idsMatch(module && module.clientCon && module.clientCon.moduleId, candidateId) ||
        idsMatch(module && module.clientCon && module.clientCon.uuid, candidateId);
}

function kioskMatchesCandidate(kiosk, candidateId) {
    const hardware = kiosk && kiosk.hardware && typeof kiosk.hardware === 'object' ? kiosk.hardware : {};
    return idsMatch(kiosk && kiosk.stationid, candidateId) ||
        idsMatch(kiosk && kiosk.id, candidateId) ||
        idsMatch(kiosk && kiosk.provisionid, candidateId) ||
        idsMatch(hardware.uuid, candidateId) ||
        idsMatch(hardware.mcuUuid, candidateId) ||
        idsMatch(hardware.clientConUuid, candidateId) ||
        idsMatch(hardware.simUUID, candidateId) ||
        idsMatch(hardware.simUuid, candidateId) ||
        idsMatch(hardware.imei, candidateId) ||
        idsMatch(hardware.sn, candidateId) ||
        idsMatch(hardware.clientCon && hardware.clientCon.moduleId, candidateId) ||
        idsMatch(hardware.clientCon && hardware.clientCon.uuid, candidateId);
}

const candidates = [];
addCandidate(candidates, moduleId);
addCandidate(candidates, info.simUUID);
addCandidate(candidates, info.deviceId);
addCandidate(candidates, aliasMap[moduleId]);
addCandidate(candidates, aliasMap[info.simUUID]);
addCandidate(candidates, aliasMap[info.deviceId]);

let matchedDoc = null;
let matchedModuleIndex = -1;
let matchedBy = '';

for (const candidateId of candidates) {
    for (const doc of docs) {
        const modules = Array.isArray(doc && doc.modules) ? doc.modules : [];
        const index = modules.findIndex((module) => moduleMatchesCandidate(module, candidateId));
        if (index >= 0) {
            matchedDoc = doc;
            matchedModuleIndex = index;
            matchedBy = candidateId;
            break;
        }
    }
    if (matchedDoc) break;
}

let matchedStationOnly = null;
let matchedStationBy = '';
if (!matchedDoc) {
    for (const candidateId of candidates) {
        matchedStationOnly = docs.find((doc) => kioskMatchesCandidate(doc, candidateId)) || null;
        if (matchedStationOnly) {
            matchedStationBy = candidateId;
            break;
        }
    }
}

const versionNumber = parseVersionNumber(hardwareVersion);

if (!matchedDoc && matchedStationOnly) {
    const kioskDoc = clone(matchedStationOnly);
    const docId = normalize(kioskDoc.provisionid || kioskDoc.id || kioskDoc._id);
    if (!docId) {
        node.error('Matched kiosk for client/con uuid ' + moduleId + ' has no provisionid/id to update', msg);
        return null;
    }

    const modules = Array.isArray(kioskDoc.modules) ? kioskDoc.modules : [];
    modules.forEach((module) => {
        if (!module || String(module.id || '').startsWith('disabled')) return;
        module.firmwareVersion = hardwareVersion;
        module.fotaVersion = hardwareVersion;
        module.firmwareVersionRaw = info.rawHardware || hardwareVersion;
        module.firmwareVersionNumber = versionNumber;
        module.firmwareVersionSource = 'client/con hardware';
        module.firmwareVersionUpdatedAt = receivedAt;
        module.clientCon = info;
        module.lastSeenHardware = hardwareVersion;
        module.lastSeenHardwareAt = receivedAt;
    });

    const hardware = kioskDoc.hardware && typeof kioskDoc.hardware === 'object' ? kioskDoc.hardware : {};
    hardware.firmwareVersion = hardwareVersion;
    hardware.fotaVersion = hardwareVersion;
    hardware.mcuVersion = hardwareVersion;
    hardware.firmwareVersionNumber = versionNumber;
    hardware.firmwareVersionSource = 'client/con hardware';
    hardware.firmwareVersionUpdatedAt = receivedAt;
    hardware.lastClientCon = info;

    msg.payload = {
        path: 'kiosks/' + docId,
        content: {
            modules,
            hardware,
            firmwareVersion: hardwareVersion,
            fotaVersion: hardwareVersion,
            firmwareVersionNumber: versionNumber,
            firmwareVersionUpdatedAt: receivedAt,
            lastFirmwareCheckAt: receivedAt
        }
    };

    node.warn('Captured client/con firmware for station ' + (kioskDoc.stationid || docId) + ' via ' + matchedStationBy + ': ' + hardwareVersion);
    return msg;
}

if (!matchedDoc) {
    msg.payload = {
        path: 'pending/' + moduleId,
        content: {
            moduleId,
            rawUuid: moduleId,
            stationid: 'pending',
            active: false,
            firmwareVersion: hardwareVersion,
            fotaVersion: hardwareVersion,
            firmwareVersionNumber: versionNumber,
            firmwareVersionSource: 'client/con hardware',
            firmwareVersionUpdatedAt: receivedAt,
            clientCon: info,
            candidateModuleIds: candidates,
            aliasHint: 'Set flow.clientConFirmwareModuleAliases if this auth uuid differs from the MQTT module id',
            lastSeen: receivedAt
        }
    };
    node.warn('Captured client/con firmware for pending module ' + moduleId + ': ' + hardwareVersion + ' candidates=' + candidates.join(','));
    return msg;
}

const kioskDoc = clone(matchedDoc);
const docId = normalize(kioskDoc.provisionid || kioskDoc.id || kioskDoc._id);
if (!docId) {
    node.error('Matched kiosk for module ' + moduleId + ' has no provisionid/id to update', msg);
    return null;
}

const modules = Array.isArray(kioskDoc.modules) ? kioskDoc.modules : [];
const targetModule = modules[matchedModuleIndex];
if (!targetModule) {
    node.error('Matched module index disappeared for ' + moduleId, msg);
    return null;
}

targetModule.firmwareVersion = hardwareVersion;
targetModule.fotaVersion = hardwareVersion;
targetModule.firmwareVersionRaw = info.rawHardware || hardwareVersion;
targetModule.firmwareVersionNumber = versionNumber;
targetModule.firmwareVersionSource = 'client/con hardware';
targetModule.firmwareVersionUpdatedAt = receivedAt;
targetModule.clientCon = info;
targetModule.clientConUuid = moduleId;
targetModule.lastSeenHardware = hardwareVersion;
targetModule.lastSeenHardwareAt = receivedAt;

const hardware = kioskDoc.hardware && typeof kioskDoc.hardware === 'object' ? kioskDoc.hardware : {};
hardware.firmwareVersion = hardwareVersion;
hardware.fotaVersion = hardwareVersion;
hardware.mcuVersion = hardwareVersion;
hardware.firmwareVersionNumber = versionNumber;
hardware.firmwareVersionSource = 'client/con hardware';
hardware.firmwareVersionUpdatedAt = receivedAt;
hardware.lastClientCon = info;

msg.payload = {
    path: 'kiosks/' + docId,
    content: {
        modules,
        hardware,
        firmwareVersion: hardwareVersion,
        fotaVersion: hardwareVersion,
        firmwareVersionNumber: versionNumber,
        firmwareVersionUpdatedAt: receivedAt,
        lastFirmwareCheckAt: receivedAt
    }
};

node.warn('Captured client/con firmware for ' + (kioskDoc.stationid || docId) + '/' + targetModule.id + ' via ' + matchedBy + ': ' + hardwareVersion);
return msg;

const path = String(msg.payload && msg.payload.path || '').trim();
if (path.startsWith('pending/')) {
    return [null, msg];
}
return [msg, null];
